// src/App.js
import React, { useState, useEffect } from "react";
import {
  BrowserRouter,
  Routes,
  Route,
  Navigate,
  useNavigate,
} from "react-router-dom";
import { onAuthChange, logoutUser } from "./utils/firebase";

import Sidebar       from "./components/Sidebar";
import DashboardPage from "./pages/DashboardPage";
import PracticePage  from "./pages/PracticePage";
import ResultsPage   from "./pages/ResultsPage";
import LandingPage   from "./pages/LandingPage";

import "./App.css";

// ─────────────────────────────────────────────────────────────────────────────
// Inner shell — rendered inside BrowserRouter so hooks work
// ─────────────────────────────────────────────────────────────────────────────
function AppShell({ user, onLogout }) {
  const navigate       = useNavigate();
  const [analysisData, setAnalysisData] = useState(null);

  // Legacy navigate helper so existing pages keep working without modification
  const legacyNavigate = (page, data = null) => {
    if (data) setAnalysisData(data);
    const routeMap = {
      landing:   "/",
      dashboard: "/dashboard",
      practice:  "/practice",
      results:   "/results",
    };
    navigate(routeMap[page] ?? "/dashboard");
  };

  return (
    <div className="app-shell">
      {/* Sidebar — only shown when logged in */}
      {user && (
        <Sidebar user={user} onLogout={onLogout} />
      )}

      {/* Main content area */}
      <main className={`app-content${user ? " with-sidebar" : ""}`}>
        <Routes>
          {/* Public route */}
          <Route
            path="/"
            element={
              user
                ? <Navigate to="/dashboard" replace />
                : <LandingPage navigate={legacyNavigate} user={user} onLogout={onLogout} />
            }
          />

          {/* Protected routes */}
          <Route
            path="/dashboard"
            element={
              user
                ? <DashboardPage navigate={legacyNavigate} user={user} onLogout={onLogout} />
                : <Navigate to="/" replace />
            }
          />
          <Route
            path="/practice"
            element={
              user
                ? <PracticePage navigate={legacyNavigate} />
                : <Navigate to="/" replace />
            }
          />
          <Route
            path="/results"
            element={
              user
                ? <ResultsPage results={analysisData} navigate={legacyNavigate} />
                : <Navigate to="/" replace />
            }
          />

          {/* Fallback */}
          <Route path="*" element={<Navigate to={user ? "/dashboard" : "/"} replace />} />
        </Routes>
      </main>
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// Root — manages auth state, wraps everything in BrowserRouter
// ─────────────────────────────────────────────────────────────────────────────
export default function App() {
  const [user, setUser] = useState(undefined); // undefined = still loading

  useEffect(() => {
    const unsub = onAuthChange((firebaseUser) => {
      setUser(firebaseUser);
    });
    return () => unsub();
  }, []);

  const handleLogout = async () => {
    await logoutUser();
    setUser(null);
  };

  // Auth loading state
  if (user === undefined) {
    return (
      <div className="app-loading">
        <div className="spinner" />
      </div>
    );
  }

  return (
    <BrowserRouter>
      <AppShell user={user} onLogout={handleLogout} />
    </BrowserRouter>
  );
}
